import dayjs from 'dayjs'
import _ from 'lodash'
import { v4 as uuidV4 } from 'uuid'

export function getHitHalfMonths(startDateStr, endDateStr) {
  // 将字符串解析为Date对象
  const startDate = new Date(startDateStr.replace(/-/g, '/'))
  const endDate = new Date(endDateStr.replace(/-/g, '/'))
  // 辅助函数：获取某个月的半月范围,定义每月的W2和W4（1-15号为W2，16-月底为W4）
  function getHalfMonthRanges(year) {
    const ranges = {}
    for (let month = 1; month <= 12; month++) {
      const wStart2 = new Date(year, month - 1, 1)
      const wEnd2 = new Date(year, month - 1, 15, 23, 59, 59)
      const wStart4 = new Date(year, month - 1, 16) //W4 开始时间 16号开始 00:00:00
      const wEnd4 = new Date(year, month, 0, 23, 59, 59)

      const monthStr = monthToStr(month)
      // w2 1-15号 23:59:59为W2，16-月底为W4 23:59:59
      ranges[`${monthStr}W2`] = {
        start: wStart2,
        end: wEnd2, // 使用修改后的结束时间
      }
      ranges[`${monthStr}W4`] = {
        start: wStart4,
        end: wEnd4,
      }
    }
    return ranges
  }

  // 辅助函数：月份数字转字符串
  function monthToStr(month) {
    const months = [
      'jan',
      'feb',
      'mar',
      'apr',
      'may',
      'jun',
      'jul',
      'aug',
      'sep',
      'oct',
      'nov',
      'dec',
    ]
    return months[month - 1]
  }

  // 获取当前年份的所有半月范围
  const year = startDate.getFullYear()
  const halfMonthRanges = getHalfMonthRanges(year)
  // 存储命中的半月
  const hitHalfMonths = []

  // 遍历所有半月，检查时间范围是否相交
  for (const halfMonth in halfMonthRanges) {
    const { start, end } = halfMonthRanges[halfMonth]
    if (startDate <= end && endDate >= start) {
      hitHalfMonths.push(halfMonth)
    }
  }
  return hitHalfMonths
}

