// 单独修改 activity 每个 W2 ,W4的比例
export const milestoneW2W4Percent = (data, mindex, aindex) => {
  const selectWeeks =
    data[mindex]['activityDetails'][aindex]['selectWeeks'] || []
  const weightOfEachWeek =
    data[mindex]['activityDetails'][aindex]['weightOfEachWeek'] || []
  const activityWeight = data[mindex]['activityDetails'][aindex]['weight']
  const activityPersonList =
    data[mindex]['activityDetails'][aindex]['activityPersonList'] || []

  const personWeightPercent = activityPersonList.map((v) => {
    return {
