  })
  data[mindex]['activityDetails'][aindex]['activityPersonList'] =
    personWeightPercent
  return data
}
export const milestonePercent = (data, mindex, aindex, changeKey) => {
  const selectWeeks =
    data[mindex]['activityDetails'][aindex]['selectWeeks'] || []
  const total = selectWeeks.length
  const activityWeight = data[mindex]['activityDetails'][aindex]['weight']
  const activityPersonList =
    data[mindex]['activityDetails'][aindex]['activityPersonList'] || []
  if (total > 0) {
    const percentageMap = {}
    let baseValue = 0
    selectWeeks.forEach((value) => {
      // 计算百分比，并精确到小数点后两位
      const percentage =
        Math.floor(
          ((selectWeeks.filter((item) => item === value).length * 100) /
            total) *
            activityWeight,
        ) / 100
      percentageMap[value] = percentage // 使用 parseFloat 将结果转换为浮点数类型存储
      baseValue = percentage
    })
    const lastMonthKey = selectWeeks[total - 1]
    const remaining = (activityWeight - baseValue * total).toFixed(2)
    percentageMap[lastMonthKey] += parseFloat(remaining)
    percentageMap[lastMonthKey] = parseFloat(
      percentageMap[lastMonthKey].toFixed(2),
    )

    const personWeightPercent = activityPersonList.map((v) => {
      return {
        ...v,
        selectWeeks: selectWeeks,
        weightOfEachWeek: multiPrincipalWeight(
          selectWeeks,
          {
            ...weightOfEachWeek,
            ...percentageMap,
          },
          activityWeight,
          v.weight,
        ),
      }
    })
    data[mindex]['activityDetails'][aindex]['activityPersonList'] =
      changeKey === 'weight' ? multiPersonInitArr : personWeightPercent
    data[mindex]['activityDetails'][aindex]['weightOfEachWeek'] = {
      ...weightOfEachWeek,
      ...percentageMap,
    }
    // data[mindex]['activityDetails'][aindex]['budget'] = weightOfEachWeek
  }
  return data
}

