export const handelActivitiesData = (data, setMilestoneTableData) => {
  data.map((item) => {
    item.weight = getActivityWeightSum(item?.activityDetails)
    item?.activityDetails.map((v) => {
      if (v.planedStartDate && v.planedEndDate) {
        const partsStart = v.planedStartDate.split('/')
        const partsEnd = v.planedEndDate.split('/')
        const startDate = `${partsStart[2]}-${partsStart[1]}-${partsStart[0]}`
        const endDate = `${partsEnd[2]}-${partsEnd[1]}-${partsEnd[0]}`
        const hitHalfMonths = getHitHalfMonths(startDate, endDate)
        v.selectWeeks = hitHalfMonths
      }
