//转换时间的格式
export const converTimeFormat = (time) => {
  const timeArr = time?.split('/')
  return `${timeArr[2]}-${timeArr[1]}-${timeArr[0]}`
}

export const truncateString = (str: string, maxLength: number) => {
  if (str.length <= maxLength) {
    return str
  }
  return str.slice(0, maxLength - 3) + '...'
}

export const handleTimeFormat = (time) => {
  const timeArr = time.split(' ')
  const timeObj = timeArr[0].split('/')
  return `${timeObj[2]}-${timeObj[1]}-${timeObj[0]} ${timeArr[1]}`
}

export const handlePlanedStartDateLogic = (startDate, endDate) => {
  if (!_.isEmpty(startDate)) {
    const nowActivityStartTime = converTimeFormat(startDate)
    if (!_.isEmpty(endDate)) {
      const nowActivityEndTime = converTimeFormat(endDate)
      const nowYear = nowActivityStartTime.split('-')[0]
      const flag =
        dayjs(nowActivityStartTime).isBefore(dayjs(nowActivityEndTime)) ||
        dayjs(nowActivityStartTime).isSame(dayjs(nowActivityEndTime))
      if (flag) {
        // 小于等于结束时间
        return dayjs(nowActivityEndTime).format('DD/MM/YYYY')
      } else {
        // 结束时间是空，开始时间今年最后一天，结束就是最后，否则结束时间自动加+1day
        return dayjs(nowActivityStartTime).isSame(dayjs(`${nowYear}-12-31`))
          ? dayjs(nowActivityStartTime).format('DD/MM/YYYY')
          : dayjs(nowActivityStartTime).add(1, 'day').format('DD/MM/YYYY')
      }
    } else {
      return dayjs(nowActivityStartTime).add(1, 'day').format('DD/MM/YYYY')
    }
  }
}

// 通过传入的开始时间，结束时间 时间区间包含的月份
export const getMonthsBetweenMonths = (startTime, endTime) => {
  const startDate = new Date(startTime)
  const endDate = new Date(endTime)
  const months = []
  const monthAbbreviations = [
    'jan',
    'feb',
    'mar',
    'apr',
    'may',
    'jun',
    'jul',
    'aug',
    'sep',
    'oct',
    'nov',
    'dec',
  ]

  // 验证日期有效性
  if (startDate > endDate) {
    return months // 返回空数组
  }

  const startYear = startDate.getFullYear()
  const startMonth = startDate.getMonth()

  const endYear = endDate.getFullYear()
  const endMonth = endDate.getMonth()

  let currentYear = startYear
  let currentMonth = startMonth

  // 循环遍历从开始日期到结束日期的所有月份
  while (currentYear === endYear && currentMonth <= endMonth) {
    months.push(monthAbbreviations[currentMonth])

    // 移动到下一个月
    currentMonth++
    if (currentMonth > 11) {
      currentMonth = 0
      currentYear++
    }
  }

  return months
}

