          <div>
            <Link
              icon={<IconEdit />}
              onClick={() => {
                setRecord([record])
                setEditDetailModalVisible(true)
              }}
            >
              {t('common:btn.edit')}
            </Link>
            <Link
              icon={<IconDelete />}
              style={{ color: '#F5626C' }}
              className='coc-table-link'
              onClick={() => handleDelete(record.id)}
            >
              {t('common:btn.delete')}
            </Link>
          </div>
        )
      },
    },
  ]
  useEffect(() => {
    if (record) {
      setTableData((prev) => {
        if (!Array.isArray(prev)) return prev
        return prev.map((item, index) => {
          const currentId = index + 1
          if (currentId !== record?.[0]?.id) return item
          return record?.[0]
        })
      })
    }
  }, [record])

  // 删除
  const handleDelete = (id) => {
    setTableData((prev) => {
      if (!Array.isArray(prev)) return prev
      return prev.filter((item, index) => index + 1 !== id)
    })
  }

  ///监听数据变化
  const handleColumnsChange = (id, key, data, value) => {
    setTableData((prev) => {
      if (!Array.isArray(prev)) return prev
      return prev.map((item, index) => {
        const currentId = index + 1
        if (currentId !== id) return item
        const newMechanism =
          key === 'measurementMechanism' ? value : item?.measurementMechanism
        return {
          ...item,
          formulas:
            newMechanism == measurementMechanismEnum['without formula']
              ? undefined
              : item?.formulas,
          [key]: value,
        }
      })
    })
  }
  // 首次生成数据
  const { run: runKpiGenerateAi, loading: kpiGenerateAiLoading } = useRequest(
    kpiGenerateAi,
    {
      manual: true,
      onSuccess: (res: any) => {
        const data = res?.map((item) => {
          return {
            ...item,
            formulas:
              item?.measurementMechanism ==
              measurementMechanismEnum['without formula']
                ? undefined
                : item?.formulas,
          }
        })
        setTableData((prev) =>
          Array.isArray(prev) && prev.length > 0 ? [...prev, ...data] : data,
        )
      },
    },
  )
  //再次生成ai数据
  const { run: runKpiRegenerateAi, loading: kpiRegenerateAiLoading } =
    useRequest(kpiRegenerateAi, {
      manual: true,
      onSuccess: (res: any) => {
        const data = res?.map((item) => {
          return {
            ...item,
            formulas:
              item?.measurementMechanism ==
              measurementMechanismEnum['without formula']
                ? undefined
                : item?.formulas,
          }
        })
        if (tableData?.length > 0) {
          setTableData((prev) => [...prev, ...data])
        } else {
          setTableData(data)
        }
      },
    })

  //发送文件进行生成
  const handelFileListSend = () => {
    const aiUploadData = {
      userIntent: allUserIntent,
      objectiveId: objectiveId,
      orgId: orgId,
      kpiType: kpiType,
      generationType: generationType,
      attachmentList: fileList,
      historyList: tableData,
    }
    if (tableData?.length > 0) {
      runKpiRegenerateAi(aiUploadData)
    } else {
      runKpiGenerateAi(aiUploadData)
    }
  }

  //获取表格数据
  const getList = useCallback(() => {
    // if (selectCycleId === 'id') {
    const data = tableData?.map((item, index) => {
      return {
        ...item,
        id: index + 1,
      }
    })
    return Promise.resolve({ list: data, total: 0 })
    // }
  }, [tableData])

  // 导出 Excel（按模板）
  const handelExportXlsx = async () => {
    if (!Array.isArray(tableData) || tableData.length === 0) return

    const monthlyData = tableData.filter(
      (item) => item.measurementCycle === measurementCycleEnum.Monthly,
    )
    const otherData = tableData.filter(
      (item) => item.measurementCycle !== measurementCycleEnum.Monthly,
    )

    const getLabelByValue = (
      options: { label: string; value: any }[],
      value: any,
    ): string => options.find((o) => o.value === value)?.label ?? ''

    const kpiTypeOptions = [
      { label: t('kpis:strategicKpi'), value: kpiTypeEnum.strategicKpi },
      { label: t('kpis:operationalKpi'), value: kpiTypeEnum.operationalKpi },
      { label: t('kpis:processKpi'), value: kpiTypeEnum.processKpi },
      { label: t('kpis:enablerKpi'), value: kpiTypeEnum.enablerKpi },
    ]

    const exportGroup = async (
      data: any[],
      templateUrl: string,
      fileName: string,
      isMonthly: boolean,
    ) => {
      const res = await fetch(templateUrl)
      const arrayBuffer = await res.arrayBuffer()

      const workbook = new ExcelJS.Workbook()
      await workbook.xlsx.load(arrayBuffer)
      const worksheet = workbook.getWorksheet('Sheet2') as any

      data.forEach((item, rowIdx) => {
        const rowNum = rowIdx + 3 // 数据从第3行开始（第2行为表头），直接覆写模板示例行
        const cycleData: any[] = item.measurementCycleData || []
        console.log('item', item)
        const row = worksheet.getRow(rowNum)
        row.getCell('A').value = cycleName || null
        row.getCell('B').value = objectiveName || null
        row.getCell('C').value = responsiblePersonEmails || null
        row.getCell('D').value = departmentName || null
        row.getCell('E').value = item.kpiName || null
        row.getCell('F').value = item.kpiNameAr || null
        row.getCell('G').value = item.description || null
        row.getCell('H').value = item.descriptionAr || null
        row.getCell('I').value = item.measurementFormulasDesc || null
        row.getCell('J').value = item.measurementFormulasDescAr || null
        row.getCell('K').value = item.startDate || null
        row.getCell('L').value = item.endDate || null
        row.getCell('M').value =
          getLabelByValue(kpiTypeOptions, kpiType) || null
        row.getCell('N').value = typeLabel || null
        row.getCell('O').value =
          getLabelByValue(measurementCycleOptionsData, item.measurementCycle) ||
          null
        row.getCell('P').value =
          getLabelByValue(measurementTypeOptions, item.measurementType) || null
        row.getCell('Q').value =
          getLabelByValue(
            measurementMechanismOptions,
            item.measurementMechanism,
          ) || null
        row.getCell('R').value =
          getLabelByValue(assemblyMethodOptions, item.assemblyMethod) || null
        row.getCell('S').value =
          getLabelByValue(measurementUnitOptions, item.measurementUnit) || null
        row.getCell('T').value =
          getLabelByValue(formulasOptions, item.formulas) || null

        // 目标值列：月度12列（U-AF，sort 1-12），季度4列（U-X，sort 1-4）
        // Annual 只有一个周期（Q4），其 sort=1 但应写入 Q4 位置（列 X）
        // Semiannual：H1→Q2（列 V），H2→Q4（列 X）
        if (item.measurementCycle === measurementCycleEnum.Annual) {
          row.getCell('X').value = cycleData[0]?.targetPerformance ?? null
        } else if (item.measurementCycle === measurementCycleEnum.Semiannual) {
          const semiannualColMap: Record<string, string> = { H1: 'V', H2: 'X' }
          cycleData.forEach((d) => {
            const col = semiannualColMap[d.code]
            if (col) row.getCell(col).value = d.targetPerformance ?? null
          })
        } else {
          const targetCols = isMonthly
            ? ['U', 'V', 'W', 'X', 'Y', 'Z', 'AA', 'AB', 'AC', 'AD', 'AE', 'AF']
            : ['U', 'V', 'W', 'X']
          targetCols.forEach((col, i) => {
            const periodData = cycleData.find((d) => d.sort === i + 1)
            row.getCell(col).value = periodData?.targetPerformance ?? null
          })
        }

        row.commit()
      })

      // 删除模板中超出实际数据行数的多余空行
      const firstExtraRow = data.length + 3
      const totalRows = worksheet.rowCount
      if (totalRows >= firstExtraRow) {
        worksheet.spliceRows(firstExtraRow, totalRows - firstExtraRow + 1)
      }

      // ExcelJS 解析模板时把范围（如 M3:M1000）展开为每个单元格地址（M3, M4...M1000）分别存入 model
      // 只需删掉数据行范围之外的地址，写入时 optimiseDataValidations 会自动合并回范围
      const dvModel: Record<string, any> =
        worksheet.dataValidations?.model ?? {}
      const lastDataRow = data.length + 2
      Object.keys(dvModel).forEach((addr) => {
        const m = addr.replace(/\$/g, '').match(/^[A-Z]+(\d+)$/)
        if (m) {
          const rowNum = parseInt(m[1], 10)
          if (rowNum < 3 || rowNum > lastDataRow) {
            delete dvModel[addr]
          }
        }
      })

      const buffer = await workbook.xlsx.writeBuffer()
      const blob = new Blob([buffer], {
        type: 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet',
      })
      const url = URL.createObjectURL(blob)
      const a = document.createElement('a')
      a.href = url
      a.download = fileName
      a.click()
      URL.revokeObjectURL(url)
    }

    if (monthlyData.length > 0) {
      await exportGroup(
        monthlyData,
        '/KPI-Monthly-template.xlsx',
        'KPI-Monthly.xlsx',
        true,
      )
    }
    if (otherData.length > 0) {
      await exportGroup(
        otherData,
        '/KPI-Quarterly-template.xlsx',
        'KPI-Quarterly.xlsx',
        false,
      )
    }
  }
  return (
    <div className='bulkKpiGeneration'>
      <div className='bulkKpiGeneration-upload'>
        <AddProjectUpload
          fileList={fileList}
          setFileList={setFileList}
          handelFileListSend={handelFileListSend}
          userIntent={allUserIntent}
          setUserIntent={setAllUserIntent}
          loading={kpiGenerateAiLoading || kpiRegenerateAiLoading}
        />
      </div>
      <div className='bulkKpiGeneration-table'>
        <div className='bulkKpiGeneration-table-title'>
          {t('kpis:add.information.title')}
        </div>
        <div className='bulkKpiGeneration-table-content'>
          <UnifiedTableStyle
            rowKey={'id'}
            noColumnWidth={80}
            noColumnFixed='left'
            loading={true}
            ref={tableRef}
            columns={columns}
            getList={getList}
          />
        </div>
      </div>
      <div className='bulkKpiGeneration-btnGroup'>
        <Button onClick={() => navigate('/strategic-kpis/kpisManagement/list')}>
          {t('common:btn.cancel')}
        </Button>
        <Button
          type='primary'
          disabled={tableData?.length === 0}
          onClick={() => handelExportXlsx()}
        >
          xlsx
        </Button>
      </div>

      <EditDetailModal
        visible={editDetailModalVisible}
        generalInfo={record}
        setGeneralInfo={setRecord}
        setTableData={setTableData}
        setVisible={setEditDetailModalVisible}
      />
    </div>
  )
}
export default BulkKpiGeneration

import { useEffect, useState, useRef } from 'react'
import { Form, Button, Modal } from '@arco-design/web-react'
import { isReadServerTextData } from '@common/constants/env'
import useLocaleTranslation from '@common/hooks/useLocaleTranslation'
import { useTranslation } from 'react-i18next'
import AddProjectUpload from '@common/components/AddProjectUpload'
import GeneralInfoAi from '../GeneralInfoAi'
import ProjectAiRegenerateIcon from '@/assets/images/icon/projectAiRegenerate-icon.svg?react'
import { useRequest } from 'ahooks'
import { useNavigate, useParams, useLocation } from 'react-router-dom'
import { kpiRegenerateAi, kpiPublishAi } from '@/service'
import { useCodeEnums } from '@common/hooks/useCodeEnums'
import dayjs from 'dayjs'
import EditableTable, {
  EditableRef,
} from '@/pages/StrategyCycle/components/EditableTable/EditableTable.tsx'
import {
  GenerationType,
  kpiTypeEnum,
  strategyApiTypeEnum,
  measurementCycleEnum,
} from '@/constants/strategicKpis'
import './index.less'

type Props = {
  visible?: any
  setVisible?: any
  generalInfo?: any
  TableData?: any
  setGeneralInfo?: any
  setMeasurementTable?: any
  setTableData?: any
}
const RegenerateModal = ({
  visible,
  setVisible,
  generalInfo,
  setGeneralInfo,
  setTableData,
}: Props) => {
  const { t } = isReadServerTextData
    ? useLocaleTranslation()
    : useTranslation(['common', 'project', 'activities'])
  const [regenerateForm] = Form.useForm()
  //////////////////////////////  project upload  ///////////////
  const [fileList, setFileList] = useState<any>([])
  const [allUserIntent, setAllUserIntent] = useState<any>()
  const location = useLocation()
  const { MONTH_ENUM } = useCodeEnums()
  const {
    objectiveId,
    cycleId,
    pillarId,
    orgId,
    type,
    kpiType,
    generationType,
  } = location.state || {}
  const [regenerateTable, setRegenerateTable] = useState<any>()
  const [regenerateInfo, setRegenerateInfo] = useState<any>()
  const tableRef = useRef<EditableRef>(null)
  const isAiRef = useRef(false)
  const endYearDate = Form.useWatch('endDate', regenerateForm)
  // 提取公共的表格行数据生成函数
  /**
   * 需求OPAB-561提出
   * ● 将“半年度”H1改为Q2，H2改为Q4。
   * ● 将“年度”改为Q4。
   */
  const yearStr = {
    Q1: t('kpis:year.Q1'),
    Q2: t('kpis:year.Q2'),
    Q3: t('kpis:year.Q3'),
    Q4: t('kpis:year.Q4'),
    H1: t('kpis:year.Q2'),
    H2: t('kpis:year.Q4'),
    ANNUAL: t('kpis:year.Q4'),
  }

  const getMeasurementName = (
    key,
    endDate,
    isYear = false,
    isMonth = false,
  ) => {
    const measurementName = `${isYear ? t('kpis:year.Q4') : isMonth ? MONTH_ENUM[key] : yearStr[key]} ${dayjs(endDate).year()}`
    return measurementName
  }

  useEffect(() => {
    const info = regenerateInfo ? regenerateInfo?.[0] : generalInfo?.[0]
    const parseDate = (val: any) =>
      typeof val === 'string' && val.includes('/')
        ? val.split('/').reverse().join('-')
        : dayjs(val).isValid()
          ? dayjs(val).format('YYYY-MM-DD')
          : undefined
    regenerateForm.setFieldsValue({
      ...info,
      startDate: parseDate(info?.startDate),
      endDate: parseDate(info?.endDate),
    })
    const isMonth = info?.measurementCycle === measurementCycleEnum.Monthly
    const isYear = info?.measurementCycle === measurementCycleEnum.Annual
    const tableData = info?.measurementCycleData?.map((item) => {
      return {
        ...item,
        key: item?.code,
        measurementName: getMeasurementName(
          item?.code,
          parseDate(info?.endDate),
          isYear,
          isMonth,
        ),
      }
    })
    isAiRef.current = false
    setRegenerateTable(tableData)
  }, [regenerateInfo, generalInfo, endYearDate])

  //再次生成
  const { run: runKpiRegenerateAi, loading: kpiRegenerateAiLoading } =
    useRequest(kpiRegenerateAi, {
      manual: true,
      onSuccess: (res: any) => {
        isAiRef.current = true
        setRegenerateInfo(res)
      },
    })
  ///Ai 生成
  const handelFileListSend = () => {
    const generalInfoData = regenerateForm.getFieldsValue()
    const aiUploadData = {
      userIntent: allUserIntent,
      objectiveId: objectiveId,
      orgId: orgId,
      kpiType: kpiType,
      generationType: generationType,
      attachmentList: fileList,
      historyList: [
        {
          ...generalInfoData,
        },
      ],
    }
    runKpiRegenerateAi(aiUploadData)
  }

  const handelPublish = () => {
    const tableRefData = tableRef.current.getData()
    const data = regenerateForm.getFieldsValue()
    let params = null
    if (generationType == GenerationType.Multi) {
      params = [
        {
          ...data,
          measurementCycleData: tableRefData,
          isModal: true,
          id: generalInfo?.[0]?.id,
        },
      ]
    } else {
      params = [
        {
          ...data,
          measurementCycleData: tableRefData,
          isModal: true,
        },
      ]
    }
    setGeneralInfo(params)
    setVisible(false)
    regenerateForm.clearFields()
  }
  const closeModal = () => {
    setVisible(false)
    regenerateForm.clearFields()
    setAllUserIntent(null)
    setFileList(null)
    setRegenerateInfo(null)
    setRegenerateTable(null)
  }
  return (
    <Modal
      visible={visible}
      style={{ width: 1020 }}
      autoFocus={false}
      focusLock={true}
      onOk={() => handelPublish()}
      okText={t('common:btn.save')}
      cancelText={t('common:btn.cancel')}
      onCancel={closeModal}
      title={t('kpis:edit.title')}
    >
      <div className='RegenerateModal'>
        <div className='RegenerateModal-addProjectUpload'>
          <AddProjectUpload
            fileList={fileList}
            setFileList={setFileList}
            handelFileListSend={handelFileListSend}
            userIntent={allUserIntent}
            setUserIntent={setAllUserIntent}
            loading={kpiRegenerateAiLoading}
          />
        </div>
        <Form
          form={regenerateForm}
          layout='vertical'
          autoComplete='off'
          className='addKpiForm'
        >
          <div className='RegenerateModal-generalInfo'>
            <GeneralInfoAi
              key={generalInfo?.[0]?.id}
              form={regenerateForm}
              measurementTable={regenerateTable}
              tableRef={tableRef}
              setMeasurementTable={setRegenerateTable}
            />
          </div>
        </Form>
      </div>
    </Modal>
  )
}
export default RegenerateModal

