import {
  Form,
  FormInstance,
  RulesProps,
  Table,
  TableProps,
} from '@arco-design/web-react'
import React, {
  forwardRef,
  ReactNode,
  useEffect,
  useImperativeHandle,
  useRef,
  useState,
} from 'react'
import EditableCell from '@/pages/StrategyCycle/components/EditableTable/components/EditableCell/EditableCell.tsx'
import { ColumnProps } from '@arco-design/web-react/es/Table'
import { v4 as uuidv4 } from 'uuid'
import { useDeepCompareLayoutEffect, useGetState } from 'ahooks'
import _ from 'lodash'
import './style/style.less'

//传入的tableData的类型，key为必传，其他字段可随意
export interface EditableDataType {
  key: string | number

  [propName: string]: any
}

//传入的table的column的配置
export interface EditableColumnType extends ColumnProps {
  editable: boolean
  type?: 'input' | 'select' | 'date' | 'filesUpdate' | 'number' | any
  //如果type 是number
  max?: number
  min?: number
  //如果type是select的options
  selectOptions?: (
    | string
    | number
    | {
        label: ReactNode | string
        value: string | number
        disabled?: boolean
        extra?: any
      }
  )[]
  //添加行时候的默认值
  defaultValue?: string | number | any[]
  //type 为number 时的后缀
  suffix?: string
  //校验规则
  rules?: RulesProps<any>[]
  placeholder?: string
}

//editable的ref类型
export interface EditableRef {
  getData: () => any
  removeRow: (key: string | number) => void
  formVerify: () => any
  formVerifyOfFields: (arg: string[]) => any
  formReset: () => void
}

type EditableProps = Omit<TableProps, 'data' | 'components' | 'columns'>

interface Props {
  //列
  columns: EditableColumnType[]
  //表数据
  tableData: EditableDataType[]
  //表配置
  tableConfig?: EditableProps
  //新增按钮DOM
  addContentJsx?: ReactNode
  //新增处理事件 复杂结构表格自己构建add的handle
  addHandle?: () => any
  //行数据改变回调，会返回最新的更改行数据
  rowChangeCallback?: (row: any) => any
  getLoadingData?: (row: any, key: string) => any
  clearDoneKey?: (key: string) => any
}

export const EditableContext = React.createContext<{
  getForm?: () => FormInstance
}>({})
const EditableTable = forwardRef(
  (
    {
      columns = [],
      tableData = [],
      tableConfig = {},
      addContentJsx = <></>,
      addHandle,
      rowChangeCallback,
      getLoadingData,
      clearDoneKey,
    }: Props,
    ref,
  ) => {
    const refForm = useRef(null)
    const getForm = () => refForm.current
    const [data, setData, getDataState] =
      useGetState<EditableDataType[]>(tableData)
    const [errorMsg, setErrorMsg] = useState(null)

    function handleSave(row) {
      const newData = [...getDataState()]
      const index = newData.findIndex((item) => row.key === item.key)
      rowChangeCallback(row)
      newData.splice(index, 1, { ...newData[index], ...row })
      setData(newData)
    }

    function removeRow(key) {
      setData(getDataState().filter((item) => item.key !== key))
    }

    function addRow() {
      if (addHandle) {
        addHandle()
      } else {
        const temp: any = {}
        columns.map((item, index) => {
          if (item.type === 'select') {
            temp[item.dataIndex] = item.defaultValue
          } else if (item.type === 'date') {
            temp[item.dataIndex] = item.defaultValue
          } else {
            temp[item.dataIndex] =
              item?.defaultValue === undefined ? '--' : item?.defaultValue
          }
        })
        temp.key = uuidv4()
        setData(getDataState().concat(temp))
      }
    }

    const [editFormStatus, setEditFormStatus, getEditFormStatus] = useGetState(
      [],
    )

    //单元格状态改变回调
    function onCellStatus(status: any) {
      if (status) {
        // let colName = temp[][Object.keys(status[Object.keys(status)[0]])[0]]
        let temp = getEditFormStatus()
        _.remove(temp, (item) => {
          return (
            item?.rowKey === status.rowKey &&
            item?.columnKey === status.columnKey
          )
        })

        temp.push(status)
        setEditFormStatus(temp)
      }
    }

    const getCurrentTableData = () => {
      const statusList = getEditFormStatus()
      if (statusList) {
        const errorItem = statusList.find((item) => item.status === false)
        if (errorItem) {
          throw new Error(errorItem?.error.message)
        } else {
          return getDataState()
        }
      }
    }
    useImperativeHandle(ref, () => ({
      getData: getCurrentTableData,
      removeRow: (key) => {
        removeRow(key)
      },
      formVerify: () => {
        return refForm.current
          .validate()
          .then((res) => {
            setErrorMsg(null)
            return getCurrentTableData()
          })
          .catch((err) => {
            const key = Object.keys(err.errors)[0]
            setErrorMsg(err.errors[key].message)
            throw err
          })
      },
      formVerifyOfFields: (fields: string[]) => {
        return refForm.current.validate(fields)
      },
      formReset: () => {
        refForm.current.resetFields()
        setData([])
      },
    }))
    // useDeepCompareLayoutEffect(() => {
    //   setData(tableData)
    // }, [tableData])
    //change useDeepCompareLayoutEffect to useEffect ,tableData may the same
    useEffect(() => {
      setData(_.cloneDeep(tableData))
    }, [tableData])
    return (
      <div className='editableContainer'>
        <div className='addHandleContainer'>
          <div onClick={addRow}>{addContentJsx}</div>
        </div>

        <Form ref={refForm} validateTrigger={[]}>
          <EditableContext.Provider
            value={{
              getForm,
            }}
          >
            <Table
              data={data}
              components={{
                body: {
                  cell: EditableCell,
                },
              }}
              columns={columns.map((column) =>
                column.editable
                  ? {
                      ...column,
                      onCell: () => ({
                        onHandleSave: handleSave,
                        onStatus: onCellStatus,
                        onHandleLoading: getLoadingData,
                        clearDoneKey: clearDoneKey,
                      }),
                    }
                  : column,
              )}
              scroll={{
                x: 'max-content',
              }}
              className='table-demo-editable-cell'
              {...tableConfig}
            />
          </EditableContext.Provider>
        </Form>

        <div
          style={{
            color: 'red',
            textAlign: 'right',
            height: 25,
          }}
        >
          {errorMsg}
        </div>
      </div>
    )
  },
)

export default EditableTable

}

